  ('dietitian-moex-00655', 'dietitian', 'dietitian-moex-112-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '進行機構內員工之人事考核與績效評估之面談，下列何者不適當？', '["面談時間要事先安排妥當以方便雙方預作準備", "面談的前幾分鐘應讓氣氛舒適以避免員工焦慮不安", "幫助員工了解改善的重要性並激勵員工改善的意願", "對工作達標項目給予讚賞或未達標者要求員工自行改善"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:51+00:00", "source_pdf_sha1": "5f26e8e9bb2a", "answer_pdf_sha1": "4e7b7a64d1c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "101", "s": "0104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
